__global__ void dynproc_kernel (int iteration,
                              int* gpuWall,
                              int* gpuSrc,
                              int* gpuResults,
                              int cols,
                              int rows,
                              int startStep,
                              int border,
                              int HALO,
                              int* prev,
                              int* result,
                              int* outputBuffer)
{
	int BLOCK_SIZE = blockDim.x;
	int bx = blockIdx.x;
	int tx = threadIdx.x;

	int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

	int blkX = (small_block_cols*bx) - border;
	int blkXmax = blkX+BLOCK_SIZE-1;

	int xidx = blkX+tx;

	int validXmin = (blkX < 0) ? -blkX : 0;
	int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

	int W = tx-1;
	int E = tx+1;

	W = (W < validXmin) ? validXmin : W;
	E = (E > validXmax) ? validXmax : E;

	bool isValid = IN_RANGE(tx, validXmin, validXmax);

	if(IN_RANGE(xidx, 0, cols-1))
	{
		prev[tx] = gpuSrc[xidx];
	}

	__syncthreads();

	bool computed;
	for (int i = 0; i < iteration; i++)
	{
		computed = false;

		if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
		{
			computed = true;
			int left = prev[W];
			int up = prev[tx];
			int right = prev[E];
			int shortest = MIN(left, up);
			shortest = MIN(shortest, right);

			int index = cols*(startStep+i)+xidx;
			result[tx] = shortest + gpuWall[index];

			if (tx==11 && i==0)
			{
				int bufIndex = gpuSrc[xidx];
				outputBuffer[bufIndex] = 1;
			}

		}

		__syncthreads();

		if(i==iteration-1)
		{
			break;
		}

		if(computed)
		{
			prev[tx] = result[tx];
		}
		__syncthreads();
	}

	if (computed)
	{
		gpuResults[xidx] = result[tx];
	}
}

#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <cuda_runtime.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define DEVICE   0
#define M_SEED   9

#define IN_RANGE(x, min, max)	((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))


int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;


int platform_id_inuse = 0;            
int device_id_inuse = 0;              

#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

	if (cols < 0 || rows < 0 || pyramid_height < 0)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v] [-p platform_id] [-d device_id] [-t device_type]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
#ifdef BENCH_PRINT
	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			printf("%d ", wall[i][j]);
		}
		printf("\n");
	}
#endif
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
	}

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    int* d_gpuWall;
    cudaMalloc(&d_gpuWall, sizeof(int) * (size - cols));

    int* d_gpuResult[2];
    cudaMalloc(&d_gpuResult[0], sizeof(int) * cols);
    cudaMalloc(&d_gpuResult[1], sizeof(int) * cols);

    int* d_outputBuffer;
    cudaMalloc(&d_outputBuffer, sizeof(int) * 16384);

    int* d_prev;
    int* d_result;
    cudaMalloc(&d_prev, sizeof(int) * 256);
    cudaMalloc(&d_result, sizeof(int) * 256);

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    cudaMemcpy(d_gpuWall, (data + cols), sizeof(int) * (size - cols), cudaMemcpyHostToDevice);
    cudaMemcpy(d_gpuResult[0], data, sizeof(int) * cols, cudaMemcpyHostToDevice);
    cudaMemcpy(d_outputBuffer, h_outputBuffer, sizeof(int) * 16384, cudaMemcpyHostToDevice);
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	int src = 1, final_ret = 0;
	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows-t-1);
		int theHalo = HALO;

#ifdef TIMING
		gettimeofday(&tv_kernel_start, NULL);
#endif
		dynproc_kernel<<<cols/256, 256>>>(arg0, d_gpuWall, d_gpuResult[src], d_gpuResult[final_ret], cols, rows, t, borderCols, theHalo, d_prev, d_result, d_outputBuffer);
#ifdef TIMING
		gettimeofday(&tv_kernel_end, NULL);
		tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
		kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
	}

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
	cudaMemcpy(result, d_gpuResult[final_ret], sizeof(int)*cols, cudaMemcpyDeviceToHost);
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	cudaMemcpy(h_outputBuffer, d_outputBuffer, sizeof(int)*16384, cudaMemcpyDeviceToHost);

	h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif
	cudaFree(d_gpuWall);
	cudaFree(d_gpuResult[0]);
	cudaFree(d_gpuResult[1]);
	cudaFree(d_outputBuffer);
	cudaFree(d_prev);
	cudaFree(d_result);
#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	delete[] data;
	delete[] wall;
	delete[] result;

#ifdef TIMING
	tvsub(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif

	return EXIT_SUCCESS;
}
